     1→import type { CompiledExperiment, TimelineNode, Trial, Stimulus } from '$lib/types/experiment';
     2→
     3→interface RenderNode {
     4→  id: string;
     5→  type: 'experiment' | 'timeline' | 'trial' | 'stimulus';
     6→  name: string;
     7→  x: number;
     8→  y: number;
     9→  width: number;
    10→  height: number;
    11→  startTime: number;
    12→  duration: number;
    13→  children?: RenderNode[];
    14→  data: any;
    15→}
    16→
    17→interface TimelineColors {
    18→  experiment: string;
    19→  timeline: string;
    20→  trial: string;
    21→  stimulus: string;
    22→  selected: string;
    23→  text: string;
    24→  grid: string;
    25→  ruler: string;
    26→}
    27→
    28→const DEFAULT_COLORS: TimelineColors = {
    29→  experiment: '#3b82f6',
    30→  timeline: '#8b5cf6',
    31→  trial: '#10b981',
    32→  stimulus: '#f59e0b',
    33→  selected: '#dc2626',
    34→  text: '#1f2937',
    35→  grid: '#e5e7eb',
    36→  ruler: '#6b7280'
    37→};
    38→
    39→export function createTimelineRenderer(ctx: CanvasRenderingContext2D) {
    40→  let experiment: CompiledExperiment | null = null;
    41→  let selectedElement: string | null = null;
    42→  let zoom = 1;
    43→  let panX = 0;
    44→  let panY = 0;
    45→  let width = 0;
    46→  let height = 0;
    47→  let renderTree: RenderNode | null = null;
    48→  let renderRequested = false;
    49→  let animationFrame: number | null = null;
    50→  
    51→  const pixelsPerMs = 0.1; // Base scale: 1 pixel = 10ms
    52→  const rowHeight = 60;
    53→  const rowGap = 10;
    54→  const nodeGap = 20;
    55→  const paddingX = 50;
    56→  const paddingY = 50;
    57→  
    58→  function setDimensions(w: number, h: number) {
    59→    width = w;
    60→    height = h;
    61→  }
    62→  
    63→  function setExperiment(exp: CompiledExperiment | null) {
    64→    experiment = exp;
    65→    if (exp) {
    66→      renderTree = buildRenderTree(exp);
    67→    } else {
    68→      renderTree = null;
    69→    }
    70→  }
    71→  
    72→  function setSelectedElement(id: string | null) {
    73→    selectedElement = id;
    74→  }
    75→  
    76→  function setZoom(z: number) {
    77→    zoom = z;
    78→  }
    79→  
    80→  function setPan(x: number, y: number) {
    81→    panX = x;
    82→    panY = y;
    83→  }
    84→  
    85→  function buildRenderTree(exp: CompiledExperiment): RenderNode {
    86→    const root: RenderNode = {
    87→      id: exp.id,
    88→      type: 'experiment',
    89→      name: exp.name,
    90→      x: 0,
    91→      y: 0,
    92→      width: 0,
    93→      height: 0,
    94→      startTime: 0,
    95→      duration: exp.duration || 0,
    96→      children: [],
    97→      data: exp
    98→    };
    99→    
   100→    let currentY = rowHeight + rowGap;
   101→    
   102→    // Build timeline nodes
   103→    exp.timelines?.forEach((timeline, tIndex) => {
   104→      const timelineNode: RenderNode = {
   105→        id: `timeline-${tIndex}`,
   106→        type: 'timeline',
   107→        name: timeline.name || `Timeline ${tIndex + 1}`,
   108→        x: 0,
   109→        y: currentY,
   110→        width: 0,
   111→        height: rowHeight,
   112→        startTime: timeline.startTime || 0,
   113→        duration: timeline.duration || 0,
   114→        children: [],
   115→        data: timeline
   116→      };
   117→      
   118→      currentY += rowHeight + rowGap;
   119→      
   120→      // Build trial nodes
   121→      timeline.trials?.forEach((trial, trIndex) => {
   122→        const trialNode: RenderNode = {
   123→          id: `trial-${tIndex}-${trIndex}`,
   124→          type: 'trial',
   125→          name: trial.name || `Trial ${trIndex + 1}`,
   126→          x: 0,
   127→          y: currentY,
   128→          width: 0,
   129→          height: rowHeight,
   130→          startTime: trial.startTime || 0,
   131→          duration: trial.duration || 0,
   132→          children: [],
   133→          data: trial
   134→        };
   135→        
   136→        currentY += rowHeight + rowGap;
   137→        
   138→        // Build stimulus nodes
   139→        trial.stimuli?.forEach((stimulus, sIndex) => {
   140→          const stimulusNode: RenderNode = {
   141→            id: `stimulus-${tIndex}-${trIndex}-${sIndex}`,
   142→            type: 'stimulus',
   143→            name: stimulus.name || `Stimulus ${sIndex + 1}`,
   144→            x: 0,
   145→            y: currentY,
   146→            width: 0,
   147→            height: rowHeight * 0.8,
   148→            startTime: stimulus.startTime || 0,
   149→            duration: stimulus.duration || 0,
   150→            data: stimulus
   151→          };
   152→          
   153→          // Calculate positions
   154→          stimulusNode.x = paddingX + (stimulusNode.startTime * pixelsPerMs * zoom);
   155→          stimulusNode.width = Math.max(50, stimulusNode.duration * pixelsPerMs * zoom);
   156→          
   157→          trialNode.children?.push(stimulusNode);
   158→        });
   159→        
   160→        // Calculate trial dimensions
   161→        trialNode.x = paddingX + (trialNode.startTime * pixelsPerMs * zoom);
   162→        trialNode.width = Math.max(100, trialNode.duration * pixelsPerMs * zoom);
   163→        
   164→        timelineNode.children?.push(trialNode);
   165→        
   166→        if (trial.stimuli && trial.stimuli.length > 0) {
   167→          currentY += (rowHeight * 0.8 + rowGap / 2) * trial.stimuli.length;
   168→        }
   169→      });
   170→      
   171→      // Calculate timeline dimensions
   172→      timelineNode.x = paddingX;
   173→      timelineNode.width = Math.max(200, timelineNode.duration * pixelsPerMs * zoom);
   174→      
   175→      root.children?.push(timelineNode);
   176→    });
   177→    
   178→    // Calculate experiment dimensions
   179→    root.width = Math.max(300, root.duration * pixelsPerMs * zoom);
   180→    root.height = currentY + paddingY;
   181→    
   182→    return root;
   183→  }
   184→  
   185→  function render() {
   186→    if (renderRequested) return;
   187→    
   188→    renderRequested = true;
   189→    
   190→    if (animationFrame) {
   191→      cancelAnimationFrame(animationFrame);
   192→    }
   193→    
   194→    animationFrame = requestAnimationFrame(() => {
   195→      renderRequested = false;
   196→      animationFrame = null;
   197→      performRender();
   198→    });
   199→  }
   200→  
   201→  function performRender() {
   202→    if (!ctx || !width || !height) return;
   203→    
   204→    // Clear canvas
   205→    ctx.clearRect(0, 0, width * window.devicePixelRatio, height * window.devicePixelRatio);
   206→    
   207→    // Save context state
   208→    ctx.save();
   209→    
   210→    // Apply device pixel ratio
   211→    ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
   212→    
   213→    // Apply pan
   214→    ctx.translate(panX, panY);
   215→    
   216→    // Calculate viewport bounds for culling
   217→    const viewportLeft = -panX;
   218→    const viewportRight = viewportLeft + width;
   219→    const viewportTop = -panY;
   220→    const viewportBottom = viewportTop + height;
   221→    
   222→    // Draw background
   223→    ctx.fillStyle = '#ffffff';
   224→    ctx.fillRect(-panX, -panY, width, height);
   225→    
   226→    // Draw grid (with culling)
   227→    drawGrid(viewportLeft, viewportRight);
   228→    
   229→    // Draw time ruler (with culling)
   230→    drawTimeRuler(viewportLeft, viewportRight);
   231→    
   232→    // Draw timeline (with culling)
   233→    if (renderTree) {
   234→      drawNodeWithCulling(renderTree, viewportLeft, viewportRight, viewportTop, viewportBottom);
   235→    }
   236→    
   237→    // Restore context state
   238→    ctx.restore();
   239→  }
   240→  
   241→  function drawGrid(viewportLeft: number, viewportRight: number) {
   242→    ctx.strokeStyle = DEFAULT_COLORS.grid;
   243→    ctx.lineWidth = 1;
   244→    ctx.setLineDash([5, 5]);
   245→    
   246→    // Vertical grid lines (time markers) - only draw visible lines
   247→    const msPerLine = 1000; // 1 second intervals
   248→    const startMs = Math.max(0, Math.floor((viewportLeft - paddingX) / (pixelsPerMs * zoom) / msPerLine) * msPerLine);
   249→    const endMs = Math.ceil((viewportRight - paddingX) / (pixelsPerMs * zoom) / msPerLine) * msPerLine;
   250→    
   251→    for (let ms = startMs; ms <= endMs; ms += msPerLine) {
   252→      const x = paddingX + (ms * pixelsPerMs * zoom);
   253→      ctx.beginPath();
   254→      ctx.moveTo(x, -panY);
   255→      ctx.lineTo(x, -panY + height);
   256→      ctx.stroke();
   257→    }
   258→    
   259→    ctx.setLineDash([]);
   260→  }
   261→  
   262→  function drawTimeRuler(viewportLeft: number, viewportRight: number) {
   263→    ctx.fillStyle = DEFAULT_COLORS.ruler;
   264→    ctx.font = '12px system-ui';
   265→    
   266→    // Draw time labels - only draw visible labels
   267→    const msPerLabel = 1000; // 1 second intervals
   268→    const startMs = Math.max(0, Math.floor((viewportLeft - paddingX) / (pixelsPerMs * zoom) / msPerLabel) * msPerLabel);
   269→    const endMs = Math.ceil((viewportRight - paddingX) / (pixelsPerMs * zoom) / msPerLabel) * msPerLabel;
   270→    
   271→    for (let ms = startMs; ms <= endMs; ms += msPerLabel) {
   272→      const x = paddingX + (ms * pixelsPerMs * zoom);
   273→      const seconds = ms / 1000;
   274→      
   275→      ctx.fillText(`${seconds}s`, x - 10, 30);
   276→    }
   277→  }
   278→  
   279→  function drawNodeWithCulling(
   280→    node: RenderNode,
   281→    viewportLeft: number,
   282→    viewportRight: number,
   283→    viewportTop: number,
   284→    viewportBottom: number
   285→  ) {
   286→    // Skip nodes outside viewport
   287→    if (node.x + node.width < viewportLeft || node.x > viewportRight ||
   288→        node.y + node.height < viewportTop || node.y > viewportBottom) {
   289→      return;
   290→    }
   291→    
   292→    // Set color based on type and selection
   293→    const isSelected = node.id === selectedElement;
   294→    ctx.fillStyle = isSelected ? DEFAULT_COLORS.selected : DEFAULT_COLORS[node.type];
   295→    
   296→    // Draw rectangle
   297→    ctx.fillRect(node.x, node.y, node.width, node.height);
   298→    
   299→    // Draw border
   300→    ctx.strokeStyle = isSelected ? DEFAULT_COLORS.selected : '#00000020';
   301→    ctx.lineWidth = isSelected ? 2 : 1;
   302→    ctx.strokeRect(node.x, node.y, node.width, node.height);
   303→    
   304→    // Draw label
   305→    ctx.fillStyle = DEFAULT_COLORS.text;
   306→    ctx.font = `${node.type === 'stimulus' ? 12 : 14}px system-ui`;
   307→    ctx.textAlign = 'left';
   308→    ctx.textBaseline = 'middle';
   309→    
   310→    // Clip text to node bounds
   311→    ctx.save();
   312→    ctx.beginPath();
   313→    ctx.rect(node.x, node.y, node.width, node.height);
   314→    ctx.clip();
   315→    
   316→    ctx.fillText(node.name, node.x + 10, node.y + node.height / 2);
   317→    
   318→    ctx.restore();
   319→    
   320→    // Draw children with culling
   321→    if (node.children) {
   322→      node.children.forEach(child => 
   323→        drawNodeWithCulling(child, viewportLeft, viewportRight, viewportTop, viewportBottom)
   324→      );
   325→    }
   326→  }
   327→  
   328→  function hitTest(x: number, y: number): RenderNode | null {
   329→    if (!renderTree) return null;
   330→    
   331→    // Apply inverse transforms
   332→    const testX = x - panX;
   333→    const testY = y - panY;
   334→    
   335→    return hitTestNode(renderTree, testX, testY);
   336→  }
   337→  
   338→  function hitTestNode(node: RenderNode, x: number, y: number): RenderNode | null {
   339→    // Test children first (they're drawn on top)
   340→    if (node.children) {
   341→      for (const child of node.children.reverse()) {
   342→        const hit = hitTestNode(child, x, y);
