// Temporary types until proper integration with @psyforge/forgescript
// These should be imported from the forgescript package once properly integrated

export interface TimelineNode {
  id: string;
  type: 'experiment' | 'timeline' | 'trial' | 'stimulus';
  name: string;
  duration?: number;
  children?: TimelineNode[];
  x?: number;
  y?: number;
  width?: number;
  height?: number;
}

export interface Stimulus {
  id?: string;
  name?: string;
  type?: string;
  startTime?: number;
  duration?: number;
  content?: any;
}

export interface Trial {
  id?: string;
  name?: string;
  startTime?: number;
  duration?: number;
  stimuli?: Stimulus[];
}

export interface Timeline {
  id?: string;
  name?: string;
  startTime?: number;
  duration?: number;
  trials?: Trial[];
}

export interface CompiledExperiment {
  id: string;
  name: string;
  description?: string;
  author?: string;
  version?: string;
  duration?: number;
  timeline?: TimelineNode[];
  timelines?: Timeline[];
}

export interface ExperimentMetadata {
  title: string;
  description?: string;
  author?: string;
  version?: string;
  created?: Date;
  modified?: Date;
}

